    ["14"]="ﻛﻬﻒ ﻏﺮﻳﺐ - ﺍﻟﻠﻬﺐ ﺍﻟﻤﻨﺬﺭ ﺑﺎﻟﺴﻮء{B}{B}ﻟﻘﺪ ﺗﻌﺜﺮﻧﺎ ﻓﻲ ﻛﻬﻒ ﻏﺮﻳﺐ ﺗﻀﻴﺌﻪ ﺃﺿﻮﺍء ﺯﺭﻗﺎء ﻣﺮﻳﺒﺔ، ﻻ ﺗﺨﺘﻠﻒ ﻋﻦ \"ﻣﺴﺘﻨﻘﻌﺎﺕ ﺍﻟﻐﻨﺎء\" ﻓﻲ ﺣﻜﺎﻳﺎﺕ ﺍﻷﻃﻔﺎﻝ. ﻭﻛﻤﺎ ﻓﻲ ﺍﻟﻘﺼﺺ ﺗﻤﺎﻣﺎ، ﻧﺎﺩﺕ ﺍﻷﺿﻮﺍء ﺭﻓﺎﻗﻲ ﻭﻧﺎﺩﺗﻨﻲ، ﻓﺘﻌﻤﻘﻨﺎ ﻓﻲ ﺃﻏﻮﺍﺭ ﺍﻟﻜﻬﻒ.{B}{B}ﺗﻤﺖ ﻣﺤﺎﺻﺮﺗﻨﺎ ﻋﻨﺪﻣﺎ ﺍﺗﺨﺬﺕ ﺍﻷﺿﻮﺍء ﺇﺷﺮﺍﻗﺎ ﻣﻬﺪﺩﺍ، ﻭﺑﺪﺃﺕ ﺟﻠﻮﺩﻧﺎ ﺗﺤﺘﺮﻕ ﺑﻨﺎﺭ ﻏﻴﺮ ﺩﻧﻴﻮﻳﺔ. ﺻﺮﺧﻨﺎ، ﻭﺭﻛﻀﻨﺎ ﺣﺘﻰ ﻟﻢ ﻧﻌﺪ ﻧﻘﻮﻯ ﻋﻠﻰ ﺍﻟﺮﻛﺾ.{B}{B}ﻛﺎﻧﺖ ﻧﻴﺮﺍﻥ ﺍﻟﻤﻌﺴﻜﺮﺍﺕ، ﺍﻟﻤﻀﺎءﺓ ﺑﺬﺍﺕ ﺍﻟﻀﻮء ﺍﻷﺯﺭﻕ، ﺗﻨﺘﺸﺮ ﻓﻲ ﺍﻟﻜﻬﻮﻑ ﺍﻟﺮﻃﺒﺔ، ﻟﻜﻨﻬﺎ ﻟﻢ ﺗﻜﻦ ﺗﺒﻌﺚ ﺃﻱ ﺩﻑء. ﻣﺠﺮﺩ ﺍﻟﺘﻮﺍﺟﺪ ﺑﺎﻟﻘﺮﺏ ﻣﻨﻬﺎ ﺧﻔﻒ ﺁﻻﻣﻨﺎ، ﻓﻘﺎﻭﻣﻨﺎ ﺗﻠﻚ ﺍﻷﺿﻮﺍء ﺍﻟﻤﺘﻮﻫﺠﺔ.{B}{B}ﻟﻘﺪ ﺭﻭﻳﻨﺎ ﻫﺬﻩ ﺍﻟﺤﻜﺎﻳﺎﺕ ﻟﻨﺨﻴﻒ ﺍﻷﻃﻔﺎﻝ ﻭﻧﺒﻌﺪﻫﻢ ﻋﻦ ﺍﻷﺭﺍﺿﻲ ﺍﻟﺮﻃﺒﺔ ﺍﻟﺨﻄﻴﺮﺓ. ﺭﺑﻤﺎ ﻛﺎﻥ ﻳﻨﺒﻐﻲ ﻟﻨﺎ ﺃﻥ ﻧﺼﻐﻲ ﻧﺤﻦ ﻷﻧﻔﺴﻨﺎ.{B}{B}ﻟﻢ ﻳﺒﻖ ﻣﻨﺎ ﺍﻵﻥ ﺳﻮﻯ ﺳﺘﺔ.",
    ["15"]="ﺍﻟﻜﻬﻒ ﺍﻟﻐﺮﻳﺐ - ﺍﻟﻤﺘﺨﺒﻂ ﺍﻟﺮﻃﺐ{B}{B}ﻟﻢ ﻳﻜﻦ ﻫﻨﺎﻙ ﺳﻮﻯ ﻃﺮﻳﻖ ﻭﺍﺣﺪ - ﺇﻟﻰ ﺍﻷﻣﺎﻡ. ﺷﻘﻘﻨﺎ ﻃﺮﻳﻘﻨﺎ ﺇﻟﻰ ﺃﻋﻤﻖ ﻣﻐﺎﻭﺭ ﺍﻟﻜﻬﻒ ﺍﻟﺮﻃﺐ، ﺗﺘﺒﻌﻨﺎ ﻫﻤﺴﺎﺕ ﺃﺭﻭﺍﺡ ﻣﻮﺗﺎﻧﺎ. ﻟﻦ ﻳﺠﺪﻭﺍ ﺃﻱ ﺭﺍﺣﺔ ﻓﻲ ﻫﺬﺍ ﺍﻟﻤﻜﺎﻥ.{B}{B}ﻓﻮﺟﺌﻨﺎ ﺑﺸﺪﺓ ﻋﻨﺪﻣﺎ ﺍﻧﻔﺼﻠﺖ ﺍﻟﻄﺤﺎﻟﺐ ﻭﺍﻷﺷﻨﺎﺕ ﺍﻟﺘﻲ ﺗﻜﺴﻮ ﺍﻟﺠﺪﺭﺍﻥ ﻋﻦ ﻣﻜﺎﻧﻬﺎ ﻭﺑﺪﺃﺕ ﺗﺘﻘﺪﻡ ﻧﺤﻮﻧﺎ ﺑﺨﻄﻰ ﻣﺘﺨﺒﻄﺔ. ﺍﻧﺒﻌﺚ ﻏﺎﺯ ﺧﺎﻧﻖ ﻣﻦ ﺑﺮﺍﻋﻤﻬﺎ ﺍﻟﻔﻄﺮﻳﺔ ﺍﻟﻤﺘﻌﺪﺩﺓ. ﻛﺎﻧﺖ ﺍﻟﻜﺮﻭﻡ ﻭﺍﻟﺴﺮﺧﺴﻴﺎﺕ ﺍﻟﺘﻲ ﺗﺸﻜﻞ ﺟﻠﺪﻫﺎ ﺗﻨﻤﻮ ﻣﻦ ﺟﺪﻳﺪ ﺑﺴﺮﻋﺔ ﻓﻲ ﻛﻞ ﻣﻜﺎﻥ ﺗﻀﺮﺏ ﻓﻴﻪ.{B}{B}ﻭﺑﻴﻨﻤﺎ ﻛﻨﺎ ﻣﺤﺎﺻﺮﻳﻦ ﻓﻲ ﺍﻟﺰﺍﻭﻳﺔ، ﻓﻌﻠﻨﺎ ﺍﻟﺸﻲء ﺍﻟﻮﺣﻴﺪ ﺍﻟﺬﻱ ﺍﺳﺘﻄﻌﻨﺎ ﻓﻌﻠﻪ. ﻋﻨﺪﻣﺎ ﺍﺧﺘﺎﺭﺕ ﺍﻟﻄﺤﺎﻟﺐ ﺿﺤﻴﺘﻬﺎ، ﻟﺬﻧﺎ ﺑﺎﻟﻔﺮﺍﺭ.{B}{B}ﺳﺘﻄﺎﺭﺩﻧﻲ ﺃﺻﺪﺍء ﺻﺮﺧﺎﺗﻪ ﺣﺘﻰ ﻧﻬﺎﻳﺔ ﺃﻳﺎﻣﻲ.",
    ["16"]="ﺍﻷﻭﺭﺩﻭﻥ - ﺣﺎﻓﻆ ﺍﻟﻘﻨﺪﻳﻞ{B}{B}ﻋﻨﺪﻣﺎ ﻋﺪﻧﺎ ﺇﻟﻰ ﻣﺨﻴﻤﻨﺎ ﺑﺎﻟﻘﺮﺏ ﻣﻦ ﺍﻟﻘﺮﻳﺔ ﺍﻟﻘﺪﻳﻤﺔ، ﻭﺟﺪﻧﺎﻩ ﻣﻨﻬﻮﺑﺎ، ﻭﻗﺪ ﺃﺣﺮﻕ ﺍﻟﻜﺜﻴﺮ ﻣﻦ ﻣﺆﻧﻨﺎ ﻓﻮﻕ ﻛﻮﻣﺔ ﺣﻄﺐ ﻋﻈﻴﻤﺔ. ﻟﻢ ﻳﻜﻦ ﻫﺬﺍ ﻣﺠﺮﺩ ﺣﻴﻮﺍﻥ - ﻓﻬﻨﺎﻙ ﺷﻲء ﻣﺎ ﺃﺭﺍﺩ ﻃﺮﺩﻧﺎ ﻣﻦ ﻫﺬﻩ ﺍﻟﺠﺰﻳﺮﺓ.{B}{B}ﻓﻲ ﺍﻟﻠﻴﻞ، ﺟﺎﺅﻭﺍ. ﻳﻨﺬﺭ ﺑﻘﺪﻭﻣﻬﻢ ﺩﻭﻱ ﺑﻮﻕ ﺣﺮﺏ ﻋﻤﻴﻖ، ﺣﻴﺚ ﻗﺎﻡ ﺭﺟﺎﻝ ﺛﻴﺮﺍﻥ ﻋﻤﺎﻟﻘﺔ ﻳﺤﻤﻠﻮﻥ ﺍﻷﺳﻠﺤﺔ ﺍﻟﻤﺸﺘﻌﻠﺔ ﺑﺠﺮ ﺛﻼﺛﺔ ﻣﻦ ﺭﺟﺎﻟﻨﺎ ﻭﻫﻢ ﻳﺼﺮﺧﻮﻥ ﺇﻟﻰ ﻏﻴﺎﻫﺐ ﺍﻟﻈﻼﻡ.{B}{B}ﺑﺰﻓﻴﺮ ﻋﻈﻴﻢ، ﻧﻔﺚ ﺃﺣﺪ ﺍﻟﺮﺟﺎﻝ ﺍﻟﺜﻴﺮﺍﻥ ﻧﻔﺜﺔ ﻣﻦ ﻟﻬﺐ ﺃﺿﺮﻣﺖ ﺍﻟﻨﺎﺭ ﻓﻲ ﻧﺼﻒ ﺍﻟﻤﺨﻴﻢ، ﻣﻤﺎ ﺷﺘﺘﻨﺎ ﻓﻲ ﺍﻷﺩﻏﺎﻝ ﻭﻏﻄﻰ ﻋﻠﻰ ﻓﺮﺍﺭﻫﻢ.{B}{B}ﻭﻣﻤﺎ ﺃﺛﺎﺭ ﺩﻫﺸﺘﻲ ﺍﻟﻌﻈﻴﻤﺔ، ﻛﺎﻧﺖ ﺃﺭﻭﺍﺡ ﺍﻟﻘﺮﻳﺔ ﻓﻲ ﺍﻧﺘﻈﺎﺭﻧﺎ ﻋﻨﺪﻣﺎ ﻋﺪﻧﺎ ﺇﻟﻰ ﺍﻟﻤﺨﻴﻢ. ﻟﻢ ﻳﺘﺤﺪﺛﻮﺍ، ﻟﻜﻨﻬﻢ ﺃﺷﺎﺭﻭﺍ ﻧﺤﻮ ﻗﻮﺱ ﺣﺠﺮﻱ ﺑﻌﻴﺪ ﻭﺃﻭﻣﺄﻭﺍ ﺑﺮﺅﻭﺳﻬﻢ. ﺭﺑﻤﺎ ﻛﺎﻧﺖ ﻧﻴﺘﻬﻢ ﻣﺴﺎﻋﺪﺗﻨﺎ؟",
    ["17"]="ﺍﻷﻭﺭﺩﻭﻥ - ﺭﻗﻴﺐ ﺍﻟﻨﺎﺭ{B}{B}ﻣﻌﺮﻛﺔ ﻋﻈﻴﻤﺔ، ﺭﺑﻤﺎ ﻛﺎﻧﺖ ﺍﻷﻋﻈﻢ ﺍﻟﺘﻲ ﺷﻬﺪﺗﻬﺎ ﻋﻠﻰ ﺍﻹﻃﻼﻕ، ﺩﺍﺭﺕ ﺭﺣﺎﻫﺎ ﻣﻦ ﺣﻮﻟﻲ ﺑﻴﻨﻤﺎ ﻛﻨﺖ ﻣﺨﺘﺒﺌﺎ ﺩﺍﺧﻞ ﺃﺣﺪ ﺻﻨﺎﺩﻳﻖ ﺍﻟﺮﺟﺎﻝ ﺍﻟﺜﻴﺮﺍﻥ ﺍﻟﻌﻤﺎﻟﻘﺔ. ﻟﻢ ﺗﻔﻌﻞ ﺑﻨﺪﻗﻴﺘﻲ ﺍﻟﻜﺜﻴﺮ ﻹﺑﻄﺎء ﻫﺠﻮﻣﻬﻢ، ﻋﻠﻰ ﺍﻟﺮﻏﻢ ﻣﻦ ﺃﻥ ﺍﻷﺭﻭﺍﺡ ﻣﻦ ﺣﻮﻟﻨﺎ ﻗﺎﺗﻠﺖ ﺑﺸﺮﺍﺳﺔ، ﻛﻤﺪ ﺻﺎﻣﺖ ﻣﻦ ﺍﻟﻤﻮﺕ ﻓﻲ ﺍﻟﻈﻼﻡ.{B}{B}ﻟﻢ ﻳﻜﻦ ﺍﻷﻭﺭﺩﻭﻥ ﻳﻔﺘﻘﺮﻭﻥ ﺇﻟﻰ ﺍﻟﺒﺮﺍﻋﺔ ﺍﻟﺴﺤﺮﻳﺔ، ﺣﻴﺚ ﺍﺳﺘﺪﻋﻮﺍ ﻛﺮﺍﺕ ﻫﺎﺋﻠﺔ ﻣﻦ ﺍﻟﻨﺎﺭ ﺍﻧﻬﻤﺮﺕ ﻋﻠﻰ ﻣﻦ ﺣﻮﻟﻬﻢ، ﻣﺴﻮﺩﺓ ﺍﻷﺭﺽ ﻣﻦ ﺣﻮﻟﻬﻢ. ﺃﺻﺎﺏ ﺃﺣﺪ ﻫﺆﻻء ﺍﻟﺴﺤﺮﺓ ﺃﺣﺪ ﺭﺟﺎﻟﻨﺎ ﻓﻲ ﺻﺪﺭﻩ ﻣﺒﺎﺷﺮﺓ ﺑﺼﺨﺮﺓ ﻧﺎﺭﻳﺔ ﺿﺨﻤﺔ، ﻣﻤﺎ ﺃﺩﻯ ﺇﻟﻰ ﻓﺼﻞ ﺟﺬﻋﻪ ﺗﻤﺎﻣﺎ ﻋﻦ ﺑﻘﻴﺔ ﺃﻃﺮﺍﻓﻪ.{B}{B}ﻓﻲ ﺧﻀﻢ ﺗﻠﻚ ﺍﻟﺠﻠﺒﺔ، ﺣﺼﻠﺖ ﻋﻠﻰ ﺑﻌﺾ ﺍﻟﺮﻣﻮﺯ ﺍﻟﻤﻨﺤﻮﺗﺔ ﻭﺍﻷﺭﺩﻳﺔ ﺍﻟﺨﺎﺻﺔ ﺑﻜﻬﻠﺔ ﺍﻟﺮﺟﺎﻝ ﺍﻟﺜﻴﺮﺍﻥ. ﺑﺒﻌﺾ ﺍﻟﻌﻤﻞ، ﻗﺪ ﺃﺗﻤﻜﻦ ﻣﻦ ﺻﻨﻊ ﺯﻱ ﻣﺎ، ﻭﺭﺑﻤﺎ ﺃﺗﻤﻜﻦ ﻣﻦ ﺇﺑﻌﺎﺩ ﺍﻵﺧﺮﻳﻦ ﻋﻦ ﻣﻮﻗﻌﻲ.",
